import React from 'react';
import {
  Container,
  Card,
  Stack,
  Heading,
  Text,
} from '@ggui-ai/design/primitives';

/**
 * Design tokens for custom styling following the ggui design system.
 * Uses the var(--ggui-*, fallback) pattern for theme compatibility.
 */
export const COLORS = {
  neutral: {
    100: 'var(--ggui-color-neutral-100, #f3f4f6)',
    200: 'var(--ggui-color-neutral-200, #e5e7eb)',
    400: 'var(--ggui-color-neutral-400, #9ca3af)',
    500: 'var(--ggui-color-neutral-500, #6b7280)',
    600: 'var(--ggui-color-neutral-600, #4b5563)',
  },
} as const;

/**
 * DashboardOverview
 * 
 * Main dashboard view component.
 * 
 * Re-aligned with ggui principles:
 * - Moved from constants.ts to ui.tsx (fixing file responsibility violation).
 * - Removed redundant BREAKPOINTS (handled by Container presets).
 * - Removed identity-map SPACING (primitives accept numeric pixel values directly).
 * - Leverages standard variants (shadow="md", maxWidth="xl") for primary styling.
 * - Uses design system variables for custom decoration.
 */
export const DashboardOverview = () => {
  return (
    <Container maxWidth="xl" padding={24}>
      <Stack gap={32}>
        {/* Page Header */}
        <Stack gap={8}>
          <Heading level={1}>Workspace Overview</Heading>
          <Text color={COLORS.neutral[500]}>
            Monitor your project progress and team activity from one place.
          </Text>
        </Stack>

        {/* Main Content Card */}
        <Card padding={24} shadow="md">
          <Stack gap={20}>
            <Heading level={2}>Monthly Performance</Heading>

            {/* Custom Analytics Visualization Placeholder */}
            <div
              style={{
                height: 200,
                backgroundColor: COLORS.neutral[100],
                borderRadius: 'var(--ggui-shape-radius-md, 8px)',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center',
                border: `1px solid ${COLORS.neutral[200]}`,
              }}
            >
              <Text color={COLORS.neutral[400]}>Analytics Visualization</Text>
            </div>

            <Text color={COLORS.neutral[600]}>
              Your team completed 24 more tasks compared to the previous month.
            </Text>
          </Stack>
        </Card>
      </Stack>
    </Container>
  );
};

export default DashboardOverview;


