import React from 'react';
import {
  Card,
  Stack,
  Text,
  Heading,
  Icon,
  Divider,
} from '@ggui-ai/design/primitives';

export interface CurrentWeatherProps {
  location: string;
  temperature: number;
  condition: string;
  description: string;
  high: number;
  low: number;
  humidity: number;
  windSpeed: number;
  iconName?: string;
}

export function CurrentWeather({
  location,
  temperature,
  condition,
  description,
  high,
  low,
  humidity,
  windSpeed,
  iconName = 'sun',
}: CurrentWeatherProps) {
  return (
    <Card shadow="md" padding={24}>
      <Stack gap={24}>
        {/* Header: Location and Icon */}
        <Stack direction="row" align="center" justify="space-between">
          <Stack gap={4}>
            <Heading level={2}>{location}</Heading>
            <Text color="muted" size="sm" weight="medium">
              {condition}
            </Text>
          </Stack>
          <Icon name={iconName} size={48} color="var(--ggui-color-primary-500)" />
        </Stack>

        {/* Main Temperature */}
        <Stack align="center" gap={8}>
          <Heading level={1} style={{ fontSize: '4rem', lineHeight: 1 }}>
            {Math.round(temperature)}°
          </Heading>
          <Text color="muted">
            H:{Math.round(high)}° L:{Math.round(low)}°
          </Text>
        </Stack>

        <Divider />

        {/* Details Grid */}
        <Stack direction="row" justify="space-around" align="center">
          <Stack align="center" gap={4}>
            <Text size="xs" color="muted" weight="bold" style={{ textTransform: 'uppercase' }}>
              Humidity
            </Text>
            <Text weight="semibold">{humidity}%</Text>
          </Stack>
          <Stack align="center" gap={4}>
            <Text size="xs" color="muted" weight="bold" style={{ textTransform: 'uppercase' }}>
              Wind
            </Text>
            <Text weight="semibold">{windSpeed} km/h</Text>
          </Stack>
          <Stack align="center" gap={4}>
            <Text size="xs" color="muted" weight="bold" style={{ textTransform: 'uppercase' }}>
              Feels Like
            </Text>
            <Text weight="semibold">{description}</Text>
          </Stack>
        </Stack>
      </Stack>
    </Card>
  );
}


// --- components/WeatherMetrics.tsx ---
import React from 'react';
import {
  Card,
  Grid,
  Heading,
  Stack,
  Text,
} from '@ggui-ai/design/primitives';

export interface WeatherMetric {
  label: string;
  value: string | number;
  unit?: string;
}

export interface WeatherMetricsProps {
  metrics: WeatherMetric[];
}

/**
 * WeatherMetrics component displays a grid of weather-related data points.
 * Refactored to follow ggui design system patterns:
 * - Replaced Stack-as-grid with Grid primitive for 2D layout.
 * - Replaced Text-as-heading with Heading primitive for semantic consistency.
 * - Replaced hardcoded inline styles with component props (size, weight, color).
 * - Removed redundant Container wrapper with full width/no padding.
 * - Cleaned up unit styling by using semantic Text instead of raw span.
 */
export function WeatherMetrics({ metrics }: WeatherMetricsProps) {
  if (!metrics || metrics.length === 0) {
    return null;
  }

  return (
    <Grid
      gap={12}
      style={{
        gridTemplateColumns: 'repeat(auto-fill, minmax(130px, 1fr))',
      }}
    >
      {metrics.map((metric, index) => (
        <Card key={`${metric.label}-${index}`} padding={16} shadow="sm">
          <Stack gap={4}>
            <Text
              size="xs"
              weight="semibold"
              color="muted"
              style={{
                textTransform: 'uppercase',
                letterSpacing: '0.05em',
              }}
            >
              {metric.label}
            </Text>
            <Stack direction="row" align="baseline" gap={2}>
              <Heading level={3}>
                {metric.value}
              </Heading>
              {metric.unit && (
                <Text size="sm" color="subtle" weight="medium">
                  {metric.unit}
                </Text>
              )}
            </Stack>
          </Stack>
        </Card>
      ))}
    </Grid>
  );
}


