// --- ui.tsx ---
// ui.tsx — main visual layout, design system primitives
import React from 'react';
import { Container, Stack, Heading, Text, Card, Divider } from '@ggui-ai/design/primitives';
import type { Props, HookReturn } from './types';
import { CurrentWeather, WeatherMetrics, ForecastStrip, ForecastItem } from './components';

export function ComponentUI(props: Props & HookReturn) {
  const { data, loading, error } = props;

  if (loading) {
    return (
      <Container padding={16}>
        <Text>Loading weather data...</Text>
      </Container>
    );
  }

  if (error || !data) {
    return (
      <Container padding={16}>
        <Text color="error">{error || 'Failed to load weather data'}</Text>
      </Container>
    );
  }

  return (
    <Container
      padding={16}
      maxWidth="xl"
    >
      <Stack gap={24}>
        <header>
          <Stack gap={4}>
            <Heading level={1}>{data.location}</Heading>
            <Text size="sm" color="muted">{new Date().toLocaleDateString()}</Text>
          </Stack>
        </header>

        <Card shadow="md" padding={24}>
          <Stack gap={20}>
            <CurrentWeather 
              temperature={data.current.temp} 
              condition={data.current.condition}
              high={data.forecast[0].high}
              low={data.forecast[0].low}
            />
            <Divider />
            <WeatherMetrics 
              humidity={data.current.humidity}
              windSpeed={data.current.windSpeed}
              uvIndex={data.current.uvIndex}
              visibility={data.current.visibility}
            />
          </Stack>
        </Card>

        <section>
          <Stack gap={16}>
            <Heading level={2}>7-Day Forecast</Heading>
            <ForecastStrip>
              {data.forecast.map((day, idx) => (
                <ForecastItem key={idx} {...day} />
              ))}
            </ForecastStrip>
          </Stack>
        </section>
      </Stack>
    </Container>
  );
}


